package fractionalknapsack

import "sort"

type item struct{ value, weight int }

// FractionalKnapsack solves the fractional knapsack problem.
func FractionalKnapsack(arr []int) int {
	capacity := arr[0]
	n := arr[1]
	items := make([]item, n)
	idx := 2
	for i := 0; i < n; i++ {
		items[i] = item{arr[idx], arr[idx+1]}
		idx += 2
	}

	sort.Slice(items, func(i, j int) bool {
		return float64(items[i].value)/float64(items[i].weight) > float64(items[j].value)/float64(items[j].weight)
	})

	totalValue := 0.0
	remaining := capacity
	for _, it := range items {
		if remaining <= 0 { break }
		if it.weight <= remaining {
			totalValue += float64(it.value)
			remaining -= it.weight
		} else {
			totalValue += float64(it.value) * float64(remaining) / float64(it.weight)
			remaining = 0
		}
	}
	return int(totalValue * 100)
}

import java.util.Arrays;

public class FractionalKnapsack {

    public static int fractionalKnapsack(int[] arr) {
        int capacity = arr[0];
        int n = arr[1];
        int[][] items = new int[n][2];
        int idx = 2;
        for (int i = 0; i < n; i++) {
            items[i][0] = arr[idx++];
            items[i][1] = arr[idx++];
        }

        Arrays.sort(items, (a, b) -> Double.compare((double) b[0] / b[1], (double) a[0] / a[1]));

        double totalValue = 0;
        int remaining = capacity;

        for (int[] item : items) {
            if (remaining <= 0) break;
            if (item[1] <= remaining) {
                totalValue += item[0];
                remaining -= item[1];
            } else {
                totalValue += (double) item[0] * remaining / item[1];
                remaining = 0;
            }
        }

        return (int)(totalValue * 100);
    }
}

fun fractionalKnapsack(arr: IntArray): Int {
    val capacity = arr[0]; val n = arr[1]
    val items = mutableListOf<Pair<Int, Int>>()
    var idx = 2
    for (i in 0 until n) { items.add(Pair(arr[idx], arr[idx + 1])); idx += 2 }
    items.sortByDescending { it.first.toDouble() / it.second }

    var totalValue = 0.0; var remaining = capacity
    for ((value, weight) in items) {
        if (remaining <= 0) break
        if (weight <= remaining) { totalValue += value; remaining -= weight }
        else { totalValue += value.toDouble() * remaining / weight; remaining = 0 }
    }
    return (totalValue * 100).toInt()
}

def fractional_knapsack(arr: list[int]) -> int:
    capacity = arr[0]
    n = arr[1]
    items = []
    idx = 2
    for _ in range(n):
        value = arr[idx]
        weight = arr[idx + 1]
        items.append((value, weight))
        idx += 2

    items.sort(key=lambda x: x[0] / x[1], reverse=True)

    total_value = 0.0
    remaining = capacity

    for value, weight in items:
        if remaining <= 0:
            break
        if weight <= remaining:
            total_value += value
            remaining -= weight
        else:
            total_value += value * remaining / weight
            remaining = 0

    return int(total_value * 100)

pub fn fractional_knapsack(arr: &[i32]) -> i32 {
    let capacity = arr[0];
    let n = arr[1] as usize;
    let mut items: Vec<(i32, i32)> = Vec::new();
    let mut idx = 2;
    for _ in 0..n {
        items.push((arr[idx], arr[idx + 1]));
        idx += 2;
    }

    items.sort_by(|a, b| {
        let ra = a.0 as f64 / a.1 as f64;
        let rb = b.0 as f64 / b.1 as f64;
        rb.partial_cmp(&ra).unwrap()
    });

    let mut total_value: f64 = 0.0;
    let mut remaining = capacity;
    for &(value, weight) in &items {
        if remaining <= 0 { break; }
        if weight <= remaining {
            total_value += value as f64;
            remaining -= weight;
        } else {
            total_value += value as f64 * remaining as f64 / weight as f64;
            remaining = 0;
        }
    }
    (total_value * 100.0) as i32
}

object FractionalKnapsack {

  def fractionalKnapsack(arr: Array[Int]): Int = {
    val capacity = arr(0); val n = arr(1)
    val items = new Array[(Int, Int)](n)
    var idx = 2
    for (i <- 0 until n) { items(i) = (arr(idx), arr(idx + 1)); idx += 2 }
    val sorted = items.sortBy(x => -x._1.toDouble / x._2)

    var totalValue = 0.0; var remaining = capacity
    for ((value, weight) <- sorted if remaining > 0) {
      if (weight <= remaining) { totalValue += value; remaining -= weight }
      else { totalValue += value.toDouble * remaining / weight; remaining = 0 }
    }
    (totalValue * 100).toInt
  }
}

func fractionalKnapsack(_ arr: [Int]) -> Int {
    let capacity = arr[0]; let n = arr[1]
    var items: [(Int, Int)] = []
    var idx = 2
    for _ in 0..<n { items.append((arr[idx], arr[idx + 1])); idx += 2 }
    items.sort { Double($0.0) / Double($0.1) > Double($1.0) / Double($1.1) }

    var totalValue = 0.0; var remaining = capacity
    for (value, weight) in items {
        if remaining <= 0 { break }
        if weight <= remaining { totalValue += Double(value); remaining -= weight }
        else { totalValue += Double(value) * Double(remaining) / Double(weight); remaining = 0 }
    }
    return Int(totalValue * 100)
}

export function fractionalKnapsack(arr: number[]): number {
    const capacity = arr[0];
    const n = arr[1];
    const items: [number, number][] = [];
    let idx = 2;
    for (let i = 0; i < n; i++) {
        items.push([arr[idx], arr[idx + 1]]);
        idx += 2;
    }

    items.sort((a, b) => b[0] / b[1] - a[0] / a[1]);

    let totalValue = 0;
    let remaining = capacity;

    for (const [value, weight] of items) {
        if (remaining <= 0) break;
        if (weight <= remaining) {
            totalValue += value;
            remaining -= weight;
        } else {
            totalValue += value * remaining / weight;
            remaining = 0;
        }
    }

    return Math.floor(totalValue * 100);
}
